class Playground {
    async run(inputs) {
        // 1. Initialize data structures
        let rootData;
        try {
            rootData = JSON.parse(inputs[0]);
        } catch (e) {
            this.log("Invalid input format. Please use [1, 2, 3]");
            return [];
        }

        this.tree.init(rootData);
        this.traversal_queue.init([]);
        this.vars.init([]);

        const root = this.tree.getRoot();
        if (!root) {
            this.log("Tree is empty.");
            return [];
        }

        const result = [];
        // Internal queue to hold node objects, slot queue for visualization
        const internalQueue = [root];
        this.traversal_queue.enqueue(root.val);

        let levelIndex = 0;
        this.vars.put("Current Level", levelIndex);
        this.log("Starting Level Order Traversal at root");
        await this.await();

        while (internalQueue.length > 0) {
            const levelSize = internalQueue.length;
            const currentLevelValues = [];
            this.vars.put("Nodes in current level", levelSize);
            this.log(`Processing Level ${levelIndex} with ${levelSize} nodes`);
            await this.await();

            for (let i = 0; i < levelSize; i++) {
                // Dequeue from both internal and visual queue
                const currentNode = internalQueue.shift();
                this.traversal_queue.dequeue();

                // Highlight the node being processed
                this.tree.highlight(currentNode.id, "#00e0ff");
                this.log(`Visiting node: ${currentNode.val}`);
                currentLevelValues.push(currentNode.val);
                await this.await();

                // Check Left Child
                if (currentNode.left) {
                    this.log(`Adding left child ${currentNode.left.val} to queue`);
                    internalQueue.push(currentNode.left);
                    this.traversal_queue.enqueue(currentNode.left.val);
                    this.tree.highlight(currentNode.left.id, "#ffb703");
                    await this.await();
                    // Reset color after adding to queue
                    this.tree.highlight(currentNode.left.id, null);
                }

                // Check Right Child
                if (currentNode.right) {
                    this.log(`Adding right child ${currentNode.right.val} to queue`);
                    internalQueue.push(currentNode.right);
                    this.traversal_queue.enqueue(currentNode.right.val);
                    this.tree.highlight(currentNode.right.id, "#ffb703");
                    await this.await();
                    // Reset color after adding to queue
                    this.tree.highlight(currentNode.right.id, null);
                }

                // Mark processed node as 'visited'
                this.tree.highlight(currentNode.id, "#00f5a0");
            }

            result.push(currentLevelValues);
            levelIndex++;
            this.vars.put("Current Level", levelIndex);
            this.log(`Finished level ${levelIndex - 1}. Current Result: ${JSON.stringify(result)}`);
            await this.await();
        }

        this.log("Traversal complete.");
        return result;
    }
}
